const resp = $input.first().json;
const input = $node['Execute Workflow Trigger'].json;

// Extract session ID from response headers
let sessionId = '';
const headers = resp.headers || {};
sessionId = headers['mcp-session-id'] || headers['Mcp-Session-Id'] || '';

// Parse SSE body to get data
let body = resp.body || resp.data || resp;
if (typeof body === 'string' && body.includes('data:')) {
  const lines = body.split('\n').filter(l => l.startsWith('data:'));
  if (lines.length > 0) {
    try { body = JSON.parse(lines[lines.length - 1].replace('data: ', '')); } catch(e) {}
  }
}

return [{
  json: {
    _session_id: sessionId,
    _bkd_url: 'https://bkd-launcher--admin-jbcnet--weifashi.coder.tbc.5ok.co/api/mcp',
    _coder_token: 'GRvtsFrbNV-7fX1P2rwfDRKwnmXsSYQEn',
    projectId: input.projectId || 'ttposhwt',
    title: input.title,
    prompt: input.prompt,
    engineType: input.engineType || 'claude-code',
    tags: input.tags || [],
    timeoutMs: input.timeoutMs || 900000,
    useWorktree: input.useWorktree !== false,
    _input: input
  }
}];

const ctx = $node['Parse Session'].json;
const raw = $input.first().json;

// Parse SSE response
let respData = raw;
if (typeof raw === 'string' || (typeof raw.data === 'string')) {
  const str = typeof raw === 'string' ? raw : raw.data;
  const lines = str.split('\n').filter(l => l.startsWith('data:'));
  if (lines.length > 0) {
    try { respData = JSON.parse(lines[lines.length - 1].replace('data: ', '')); } catch(e) {}
  }
}

let issueData = {};
try {
  const text = respData.result?.content?.[0]?.text || '{}';
  issueData = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  issueData = respData;
}

return [{
  json: {
    ...ctx,
    issueId: issueData.id || issueData.issueId,
    _poll_start: Date.now(),
    _poll_count: 0
  }
}];

const raw = $input.first().json;
const ctx = $node['Parse Issue ID'].json;

// Parse SSE
let respData = raw;
if (typeof raw === 'string' || (typeof raw.data === 'string')) {
  const str = typeof raw === 'string' ? raw : raw.data;
  const lines = str.split('\n').filter(l => l.startsWith('data:'));
  if (lines.length > 0) {
    try { respData = JSON.parse(lines[lines.length - 1].replace('data: ', '')); } catch(e) {}
  }
}

let issue = {};
try {
  const text = respData.result?.content?.[0]?.text || '{}';
  issue = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  issue = respData;
}

const status = issue.statusId || issue.status || 'unknown';
const elapsed = Date.now() - ctx._poll_start;
const pollCount = (ctx._poll_count || 0) + 1;

return [{
  json: {
    ...ctx,
    _status: status,
    _still_working: (status === 'working'),
    _timed_out: (elapsed >= ctx.timeoutMs),
    _poll_count: pollCount,
    _elapsed_ms: elapsed
  }
}];

const ctx = $node['Parse Issue ID'].json;
return [{
  json: {
    success: false,
    issueId: ctx.issueId,
    error: 'Stage timed out after ' + Math.round(ctx.timeoutMs / 1000) + 's',
    output: null,
    _input: ctx._input
  }
}];

const raw = $input.first().json;
const ctx = $node['Parse Issue ID'].json;

// Parse SSE
let respData = raw;
if (typeof raw === 'string' || (typeof raw.data === 'string')) {
  const str = typeof raw === 'string' ? raw : raw.data;
  const lines = str.split('\n').filter(l => l.startsWith('data:'));
  if (lines.length > 0) {
    try { respData = JSON.parse(lines[lines.length - 1].replace('data: ', '')); } catch(e) {}
  }
}

let logs = {};
try {
  const text = respData.result?.content?.[0]?.text || '{}';
  logs = typeof text === 'string' ? JSON.parse(text) : text;
} catch(e) {
  logs = respData;
}

let output = null;
let success = false;
const entries = logs.entries || logs.messages || [];
for (let i = entries.length - 1; i >= 0; i--) {
  const entry = entries[i];
  const content = entry.content || entry.text || '';
  if (entry.role === 'assistant' || entry.type === 'assistant-message') {
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      try {
        output = JSON.parse(jsonMatch[0]);
        success = output.success === true || output.accepted === true;
      } catch(e) {
        output = content;
      }
    } else {
      output = content;
    }
    break;
  }
}

const sessionStatus = logs.sessionStatus || ctx._status;
if (sessionStatus === 'failed' || sessionStatus === 'cancelled') {
  success = false;
}

return [{
  json: {
    success: success,
    issueId: ctx.issueId,
    sessionStatus: sessionStatus,
    output: output,
    error: success ? null : (output?.error_summary || output?.error || 'Stage failed'),
    _input: ctx._input
  }
}];
